mapper.select:
SELECT id, warehouse_id, sku_id, available, locked, version, create_time, update_time
FROM tb_stock
WHERE warehouse_id = #{warehouseId}
  AND sku_id = #{skuId}
LIMIT 1

mapper.update:
UPDATE tb_stock
SET available = available - #{quantity},
    update_time = NOW()
WHERE warehouse_id = #{warehouseId}
  AND sku_id = #{skuId}
  AND available >= #{quantity}
